// --- types.d.ts ---
export interface ForecastData {
  day: string;
  icon: string;
  high: number;
  low: number;
}

export interface WeatherProps {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit?: string;
  forecast: ForecastData[];
}

export interface WeatherHookReturn {
  formattedTemp: string;
  formattedWind: string;
  formattedHumidity: string;
  conditionIcon: string;
  forecastItems: ForecastData[];
  displayUnit: string;
}

export interface CurrentWeatherProps {
  city: string;
  temperature: string;
  condition: string;
  icon: string;
}

export interface WeatherDetailItemProps {
  label: string;
  value: string;
  icon: string;
}

export interface WeatherDetailsProps {
  humidity: string;
  windSpeed: string;
}

export interface ForecastStripProps {
  forecast: ForecastData[];
  unit: string;
}

export interface ForecastItemProps {
  data: ForecastData;
  unit: string;
}


// --- constants.ts ---
// constants.ts — static data, mappings, configurations

export const CONDITION_ICONS: Record<string, string> = {
  'Sunny': '☀️',
  'Clear': '☀️',
  'Partly Cloudy': '⛅',
  'Cloudy': '☁️',
  'Overcast': '☁️',
  'Rain': '🌧️',
  'Showers': '🌦️',
  'Thunderstorm': '⛈️',
  'Snow': '❄️',
  'Fog': '🌫️',
};

export const UNIT_SYMBOLS: Record<string, string> = {
  'C': '°C',
  'metric': '°C',
  'F': '°F',
  'imperial': '°F',
};

export const HUMIDITY_LABEL = "Humidity";
export const WIND_SPEED_LABEL = "Wind Speed";
export const WIND_SPEED_UNIT = "km/h";


// --- hooks.ts ---
import { useMemo } from 'react';
import type { WeatherProps, WeatherHookReturn } from './types';

export function useWeather(props: WeatherProps): WeatherHookReturn {
  const {
    temperature,
    condition,
    humidity,
    windSpeed,
    unit = 'metric',
    forecast = [],
  } = props;

  return useMemo(() => {
    const isMetric = unit === 'metric' || !unit;
    const displayUnit = isMetric ? '°C' : '°F';
    const windUnit = isMetric ? 'km/h' : 'mph';

    const formattedTemp = `${temperature}${displayUnit}`;
    const formattedWind = `${windSpeed} ${windUnit}`;
    const formattedHumidity = `${humidity}%`;

    const getConditionIcon = (cond: string): string => {
      const normalizedCondition = cond.toLowerCase();
      if (normalizedCondition.includes('sun') || normalizedCondition.includes('clear')) return '☀️';
      if (normalizedCondition.includes('cloud')) return '☁️';
      if (normalizedCondition.includes('rain') || normalizedCondition.includes('drizzle')) return '🌧️';
      if (normalizedCondition.includes('snow')) return '❄️';
      if (normalizedCondition.includes('storm') || normalizedCondition.includes('thunder')) return '⛈️';
      return '☁️'; // Default fallback
    };

    return {
      formattedTemp,
      formattedWind,
      formattedHumidity,
      conditionIcon: getConditionIcon(condition),
      forecastItems: forecast,
      displayUnit,
    };
  }, [temperature, condition, humidity, windSpeed, unit, forecast]);
}


// --- components/CurrentWeather.tsx ---
import React from 'react';
import {
  Container,
  Card,
  Stack,
  Heading,
  Text,
  Icon,
} from '@ggui-ai/design/primitives';
import { WeatherProps } from './types';

/**
 * Maps weather condition strings to emojis.
 * In a real-world scenario, this might return specific icon components.
 */
const getConditionEmoji = (condition: string): string => {
  const cond = condition.toLowerCase();
  if (cond.includes('sun') || cond.includes('clear')) return '☀️';
  if (cond.includes('cloud') || cond.includes('overcast')) return '☁️';
  if (cond.includes('rain') || cond.includes('drizzle') || cond.includes('shower')) return '🌧️';
  if (cond.includes('thunder') || cond.includes('storm')) return '⛈️';
  if (cond.includes('snow') || cond.includes('flurry')) return '❄️';
  if (cond.includes('fog') || cond.includes('mist')) return '🌫️';
  return '⛅';
};

/**
 * CurrentWeather component displays the current weather summary,
 * key meteorological details, and a 5-day forecast.
 */
export function CurrentWeather({
  city,
  temperature,
  condition,
  humidity,
  windSpeed,
  unit = '°C',
  forecast,
}: WeatherProps) {
  const currentEmoji = getConditionEmoji(condition);

  return (
    <Container maxWidth="md">
      <Card
        shadow="md"
        padding={32}
        aria-label={`Current weather in ${city}`}
      >
        <Stack gap="var(--ggui-spacing-lg, 24px)">
          {/* Current Weather Header */}
          <Stack direction="horizontal" justify="between" align="center">
            <Stack gap={8}>
              <Heading level={1}>{city}</Heading>
              <Text size="lg" color="var(--ggui-color-neutral-500, #6b7280)">
                {condition}
              </Text>
            </Stack>

            <Stack direction="horizontal" align="center" gap={16}>
              <Text style={{ fontSize: '3rem' }} aria-hidden="true">
                {currentEmoji}
              </Text>
              <Heading
                level={1}
                style={{
                  fontSize: 'var(--ggui-font-size-6xl, 4rem)',
                  color: 'var(--ggui-color-primary-600, #0284c7)',
                  margin: 0,
                }}
              >
                {temperature}{unit}
              </Heading>
            </Stack>
          </Stack>

          {/* Weather Details Section */}
          <Stack direction="horizontal" gap={24} align="center">
            <Stack direction="horizontal" gap={8} align="center">
              <Icon size={20}>
                <span role="img" aria-label="Humidity">💧</span>
              </Icon>
              <Text variant={"secondary" as any}>
                Humidity: {humidity}%
              </Text>
            </Stack>
            <Stack direction="horizontal" gap={8} align="center">
              <Icon size={20}>
                <span role="img" aria-label="Wind speed">💨</span>
              </Icon>
              <Text variant={"secondary" as any}>
                Wind: {windSpeed} {unit}
              </Text>
            </Stack>
          </Stack>

          {/* Horizontal Separator */}
          <div
            style={{
              borderTop: '1px solid var(--ggui-color-neutral-200, #e5e7eb)',
              margin: '24px 0',
            }}
          />

          {/* 5-Day Forecast Strip */}
          <Stack direction="horizontal" gap={16} justify="between">
            {forecast.slice(0, 5).map((item, index) => (
              <Stack key={`${item.day}-${index}`} gap={8} align="center">
                <Text variant="label" size="sm">
                  {item.day}
                </Text>
                <Text size="2xl" aria-hidden="true">
                  {item.icon || getConditionEmoji(condition)}
                </Text>
                <Text size="xs" color="var(--ggui-color-neutral-500, #6b7280)">
                  {item.high}° / {item.low}°
                </Text>
              </Stack>
            ))}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}


