import React from 'react';
import { Stack, Text } from '@ggui-ai/design/primitives';
import { WeatherDetailsProps, WeatherDetailItemProps } from '../types';

/**
 * Internal helper component for a single weather detail metric.
 * Layout: Vertical stack (flex-column).
 * Label: var(--ggui-color-neutral-500) text color, small font size.
 * Value: var(--ggui-color-neutral-900), semi-bold weight.
 * Icon: Displayed next to the label.
 */
const WeatherDetailItem: React.FC<WeatherDetailItemProps> = ({ label, value, icon }) => {
  return (
    <Stack gap="var(--ggui-space-2, 8px)" align="center">
      <Stack direction="horizontal" gap="var(--ggui-space-1, 4px)" align="center">
        <span aria-hidden="true" style={{ fontSize: 'var(--ggui-font-size-base, 16px)', display: 'flex' }}>
          {icon}
        </span>
        <Text
          size="sm"
          color="var(--ggui-color-neutral-500, #6b7280)"
          as="span"
        >
          {label}
        </Text>
      </Stack>
      <Text
        weight="semibold"
        color="var(--ggui-color-neutral-900, #111827)"
        size="base"
        as="span"
      >
        {value}
      </Text>
    </Stack>
  );
};

/**
 * WeatherDetails component showing humidity and wind speed.
 * Wrapped in a div with aria-label="Weather Details".
 * Uses flexbox with space-between distribution.
 * padding: var(--ggui-space-4, 16px) top and bottom.
 * border-top: 1px solid var(--ggui-color-neutral-100).
 */
export const WeatherDetails: React.FC<WeatherDetailsProps> = ({
  humidity,
  windSpeed,
}) => {
  return (
    <section
      aria-label="Weather Details"
      style={{
        display: 'flex',
        justifyContent: 'space-between',
        padding: 'var(--ggui-space-4, 16px) 0',
        borderTop: '1px solid var(--ggui-color-neutral-100, #f3f4f6)',
      }}
    >
      <WeatherDetailItem
        label="Humidity"
        value={humidity}
        icon="💧"
      />
      <WeatherDetailItem
        label="Wind Speed"
        value={windSpeed}
        icon="💨"
      />
    </section>
  );
};

export default WeatherDetails;


// --- components/ForecastStrip.tsx ---
import React from 'react';
import { Stack, Text, Box } from '@ggui-ai/design/primitives';
import type { ForecastStripProps, ForecastItemProps } from '../types';

/**
 * Helper component for individual forecast items
 */
function ForecastItem({ data, unit }: ForecastItemProps) {
  return (
    <Stack direction="vertical" align="center" gap={4}>
      <Text
        weight="bold"
        size="sm"
        color="var(--ggui-color-neutral-600, #4b5563)"
      >
        {data.day}
      </Text>

      <Box paddingY={4}>
        <div 
          style={{ 
            fontSize: '1.5rem', 
            lineHeight: 1,
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center'
          }} 
          aria-hidden="true"
        >
          {data.icon}
        </div>
      </Box>

      <Stack direction="horizontal" gap={4}>
        <Text weight="medium">
          {data.high}{unit}
        </Text>
        <Text color="var(--ggui-color-neutral-500, #6b7280)">
          {data.low}{unit}
        </Text>
      </Stack>
    </Stack>
  );
}

/**
 * ForecastStrip - Displays a multi-day weather forecast in a horizontal layout.
 */
export function ForecastStrip({ forecast, unit }: ForecastStripProps) {
  return (
    <section 
      aria-label="5-day weather forecast" 
      style={{ 
        width: '100%', 
        overflowX: 'auto',
        padding: 'var(--ggui-spacing-4, 16px) 0'
      }}
    >
      <Stack
        direction="horizontal"
        justify="between"
        gap={12}
        align="center"
      >
        {forecast.map((item, index) => (
          <ForecastItem 
            key={`${item.day}-${index}`} 
            data={item} 
            unit={unit} 
          />
        ))}
      </Stack>
    </section>
  );
}


// --- components/ForecastItem.tsx ---
import React from 'react';
import { Stack, Text } from '@ggui-ai/design/primitives';
import type { ForecastItemProps } from '../types';

/**
 * ForecastItem component displays weather forecast details for a single day.
 * It follows a vertical layout with accessibility support for screen readers.
 */
export function ForecastItem({ data, unit }: ForecastItemProps) {
  return (
    <Stack
      direction="vertical"
      align="center"
      gap={8}
      role="listitem"
      aria-label={`${data.day}: High ${data.high}${unit}, Low ${data.low}${unit}`}
    >
      {/* Day Name */}
      <Text size="sm" color="var(--ggui-color-neutral-500, #6b7280)">
        {data.day}
      </Text>

      {/* Weather Icon */}
      <span style={{ fontSize: 'var(--ggui-font-size-2xl, 24px)' }}>
        {data.icon}
      </span>

      {/* Temperatures */}
      <Stack direction="horizontal" gap={4}>
        {/* High Temperature */}
        <Text weight="bold" color="var(--ggui-color-neutral-900, #111827)">
          {data.high}{unit}
        </Text>

        {/* Low Temperature */}
        <Text color="var(--ggui-color-neutral-400, #9ca3af)">
          {data.low}{unit}
        </Text>
      </Stack>
    </Stack>
  );
}


// --- ui.tsx ---
import React from 'react';
import { Container, Card, Stack } from '@ggui-ai/design/primitives';
import { CurrentWeather, WeatherDetails, ForecastStrip } from './components';
import { useWeather } from './hooks';
import { WeatherProps } from './types';

export const WeatherCard: React.FC<WeatherProps> = (props) => {
  const {
    formattedTemp,
    formattedWind,
    formattedHumidity,
    conditionIcon,
    displayUnit,
  } = useWeather(props);

  return (
    <Container maxWidth="md" padding={24}>
      <Card shadow="md" padding={32} radius="lg">
        <Stack gap="var(--ggui-spacing-8, 32px)">
          {/* Top Section: Current Weather */}
          <CurrentWeather
            city={props.city}
            temperature={formattedTemp}
            condition={props.condition}
            icon={conditionIcon}
          />

          {/* Middle Section: Weather Details */}
          <WeatherDetails
            humidity={formattedHumidity}
            windSpeed={formattedWind}
          />

          {/* Bottom Section: Forecast */}
          <ForecastStrip 
            forecast={props.forecast} 
            unit={displayUnit} 
          />
        </Stack>
      </Card>
    </Container>
  );
};


// --- render.tsx ---
// render.tsx — entry point
import React from 'react';
import type { Props } from './types';
import { useComponent } from './hooks';
import { ComponentUI } from './ui';

export default function Component(props: Props) {
  const state = useComponent(props);
  return <ComponentUI {...props} {...state} />;
}
